_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;



vec2 uv1 = (vUv-.5);// * uAspect.xy;
vec2 uv2 = vec2(abs(fract(uv1.x)-.5),abs(fract(uv1.y)-.5))*2;


vec3 stars = (.1/length(sin(uv2*6.28)));
stars *= 4*pow(texture(sampler_noise_hq,uv2/16),2);
ret = pow(stars,1+vRadius*.3);

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;
  uv0 = vUv;
screen3 = vec3 ((vUv-.5)*uAspect.xy,1) * (1+.0*texture(sampler_noise_hq,vUv+uTime*.1));

dist = .5; lav_gnd = 0; tower = 1;
for (int m=1; m <= quality; m++) {
  rsl = project (dist)+vec3 (mov,0);
  lprof =  (texture(sampler_pw_noise_lq,rsl.xy*.1).r <=.7);
  uv2 = rsl.xy*.4*64;
  tile = clamp01(2-3*max(abs(fract(uv2.x)-.5),abs(fract(uv2.y)-.5)))*.25+.75;
  lprof = 1-clamp01(1-lprof)*tile;
  lprof *= texture(sampler_pw_noise_lq,rsl.xy*.1/16+tower+q30).r;
  lav_gnd -= lprof/quality*depth/rsl.z;
  tower -= lprof/quality/2;
  rsl3 = rsl;
}
rsl = project (dist)+vec3 (mov,0);
float step = int(uTime*8)%14+q24;
float mask =         texture(sampler_pw_noise_lq,rsl.xy+step/128).r >= .9;
mask *=              texture(sampler_pw_noise_lq,rsl.xy + 1.0/8*int(tower*8)).r >= .9;
vec3 windows = pow(texture(sampler_pw_noise_lq,rsl.xy),2).r* !mask;


uv2 = rsl.xy*4*64;

tile = clamp01(1-2*max(abs(fract(uv2.x)-.5),abs(fract(uv2.y)-.5)));
windows *= 2*tile*GetPixel(fract(rsl.xy*2));

lav_gnd = 0;
rsl2 = project(dist) + vec3 (mov,0);
vec3 light = GetPixel(fract(rsl2*2));
ret1 =  mix(8*light*clamp01(1-tower),2*windows *(tower*2-1),clamp01(2*tower-1.1)) ;

uv4 = vec2(fract(rsl.x),fract(rsl.y));
ret1 *= 1+pow(sin(4*(uv4.x/uv4.y)+8*uTime),24) *(q28%4 ==1)* roam_sin ;;

ret = 1-exp(-ret1*2);
//ret = GetPixel(vUv);

  fragColor = ret;
}
